import { Layout } from 'antd';
import React, { useState } from 'react';

import Login from './MainView/Login';
import MainMenu from './MainView/MainMenu';

import logo from './logo.jpg';
import './App.css';
import Dashboard from './MainView/Dashboard';
import VehicleBrand from './MainView/VehicleBrand';
import VehicleModel from './MainView/VehicleModel';
import Client from './MainView/Client';
import Office from './MainView/Office';
import ExcludedArea from './MainView/ExcludedArea';
import Driver from './MainView/Driver';
import Dispatcher from './MainView/Dispatcher';
import Passenger from './MainView/Passenger';
import Tour from './MainView/Tour';
import User from './MainView/User';
import Role from './MainView/Role';
import Permission from './MainView/Permission';

const { Header, Footer, Sider, Content } = Layout;

const Components = {
  'Dashboard': Dashboard,
  'VehicleBrand': VehicleBrand,
  'VehicleModel': VehicleModel,
  'Client': Client,
  'Office': Office,
  'ExcludedArea': ExcludedArea,
  'Driver': Driver,
  'Dispatcher': Dispatcher,
  'Passenger': Passenger,
  'Tour': Tour,
  'User': User,
  'Role': Role,
  'Permission': Permission,
}

function App() {

  const [activeSection, setActiveSection] = useState('VehicleBrand');

  const onMenuSectionClick = section => setActiveSection(section)

  const CurrentSection = Components[activeSection];

  return (
    <>
      {false && <Login />}
      {true && <Layout>
        <Sider width={255}>
          <img className='logo' src={logo} />
          <MainMenu onClick={onMenuSectionClick} />
        </Sider>
        <Layout>
          <Header>Header</Header>
          <Content>
            <CurrentSection />
          </Content>
          <Footer>Footer</Footer>
        </Layout>
      </Layout>}
    </>
  );
}

export default App;
