import { DashboardOutlined, CarOutlined, TeamOutlined, NodeIndexOutlined, SettingOutlined, BarChartOutlined } from '@ant-design/icons';
import { Menu } from 'antd';


function getItem(label, key, icon, children, type) {
    return {
        key,
        icon,
        children,
        label,
        type,
    };
}

const items = [
    getItem('Dashboard', 'Dashboard', <DashboardOutlined />),
    getItem('Vehículos', '', <CarOutlined />, [
        getItem('Marcas', 'VehicleBrand'),
        getItem('Modelos', 'VehicleModel'),
        getItem('Listado', 'Vehicle'),
    ]),
    getItem('Clientes', '', <TeamOutlined />, [
        getItem('Listado', 'Client'),
        getItem('Oficinas', 'Office'),
    ]),
    getItem('Recorridos', '', <NodeIndexOutlined />, [
        getItem('Zonas Excluidad', 'ExcludedArea'),
        getItem('Choferes', 'Driver'),
        getItem('Expedidores', 'Dispatcher'),
        getItem('Pasajeros', 'Passenger'),
        getItem('Listado', 'Tour'),
    ]),
    getItem('Transpriem', '', <SettingOutlined />, [
        getItem('Usuarios', 'User'),
        getItem('Roles', 'Role'),
        getItem('Permission', 'Permission'),
    ]),
    // getItem('Reportes', '6', <BarChartOutlined />, [
    //     getItem('Usuarios', '6.1'),
    //     getItem('Roles', '6.2'),
    //     getItem('Reportes', '6.3'),
    // ]),
];

export default function MainMenu(props) {

    const {onClick} = props;

    const handleClick = (e) => onClick(e.key)

    return (
        <Menu
            onClick={handleClick}
            style={{
                width: 256,
            }}
            defaultSelectedKeys={['1']}
            defaultOpenKeys={['1', '2', '3', '4', '5']}
            mode="inline"
            items={items}
        />
    );
}