import React from 'react';

import { InboxOutlined, UploadOutlined } from '@ant-design/icons';

import {
  Button,
  Checkbox,
  Col,
  Form,
  Input,
  InputNumber,
  Radio,
  Rate,
  Row,
  Select,
  Slider,
  Switch,
  Upload,
} from 'antd';

import axios from "axios";

import { useForm } from "react-hook-form";

const { Option } = Select;

const FormData = require('form-data');

export default function VehicleBrand(props) {
    const {url='http://transpriem/brands'} = props;
    return (
        <VehicleForm url={url} />
    );
}

const formItemLayout = {
    labelCol: {
        span: 6,
    },
    wrapperCol: {
        span: 14,
    },
};

const normFile = (e) => {
    console.log('Upload event:', e);

    if (Array.isArray(e)) {
        return e;
    }

    return e?.fileList;
};

const VehicleForm = (props) => {
    const {url} = props;
    const onFinish = (data) => {

        const form = new FormData();

        Object.keys(data).forEach(key => {
            form.append(key, data[key]);
        });

        // form.append('my_buffer', new Buffer(10));
        // form.append('my_file', fs.createReadStream('/foo/bar.jpg'));

        axios.post(url, form, { headers: { 'content-type': 'application/x-www-form-urlencoded' } });

        // console.log('Received values of form: ', values);
    };

    return (
        <Form
            name="validate_other"
            {...formItemLayout}
            onFinish={onFinish}
            initialValues={{
                'input-number': 3,
                'checkbox-group': ['A', 'B'],
                rate: 3.5,
            }}
        >
            <Form.Item label="Plain Text">
                <span className="ant-form-text">China</span>
            </Form.Item>

            <Form.Item label="Name">
                <Form.Item name="brand_name" noStyle>
                    <Input />
                </Form.Item>
            </Form.Item>

            <Form.Item
                name="upload"
                label="Upload"
                valuePropName="fileList"
                getValueFromEvent={normFile}
                extra=""
            >
                <Upload name="logo" action={`${url}/upload/logo`} listType="picture">
                    <Button icon={<UploadOutlined />}>Click to upload</Button>
                </Upload>
            </Form.Item>

            <Form.Item
                wrapperCol={{
                    span: 12,
                    offset: 6,
                }}
            >
                <Button type="primary" htmlType="submit">
                    Submit
                </Button>
            </Form.Item>
        </Form>
    );
};